mapper.select:
SELECT p.PLACE_ID as placeId, p.PLACE_NAME as name, p.IMAGE_URL as imageUrl, p.ADDRESS as region, a.ACCOMMODATION_TYPE as accommodationType, MIN(r.AMOUNT) as minPrice FROM PLACE p JOIN ACCOMMODATION a ON p.PLACE_ID = a.PLACE_ID JOIN ROOM r ON a.PLACE_ID = r.PLACE_ID JOIN ACCOMMODATION_FACILITY af ON a.AF_ID = af.AF_ID JOIN ROOM_FACILITY rf ON r.RF_ID = rf.RF_ID WHERE 1=1
AND p.ADDRESS LIKE '%' || #{region} || '%'
AND a.ACCOMMODATION_TYPE IN
#{type}
AND r.AMOUNT >= #{minPrice}
AND r.AMOUNT <= #{maxPrice}
AND r.MAX_CAPACITY >= (#{adult} + #{child})
AND af.FITNESS = 1 AND af.CHKCOOKING = 1 AND af.BARBECUE = 1 AND af.BEVERAGE = 1 AND af.KARAOKE = 1 AND af.PUBLICPC = 1 AND af.SAUNA = 1
GROUP BY p.PLACE_ID, p.PLACE_NAME, p.IMAGE_URL, p.ADDRESS, a.ACCOMMODATION_TYPE

SELECT IMAGE_URL 
FROM ACCOMMODATION_IMAGE 
WHERE PLACE_ID = #{placeId}
